import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.previewer.PreviewerFragment
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.`is`
import org.junit.Test
import org.junit.runner.RunWith
import org.robolectric.annotation.Config

/**
 * Test that verifies the Android back button works correctly in SingleFragmentActivity
 * and its subclasses (like PreviewerActivity).
 *
 * This test addresses the bug where the back button didn't close the previewer.
 */
@RunWith(AndroidJUnit4::class)
@Config(qualifiers = "en")
class SingleFragmentActivityBackButtonTest : RobolectricTest() {

    /**
     * Tests that when a fragment doesn't handle a key event (returns false),
     * the event is properly delegated to the parent's dispatchKeyEvent implementation.
     */
    @Test
    fun backButtonIsHandledWhenFragmentDoesNotHandleIt() {
        // Create an intent for SingleFragmentActivity with a test fragment
        val intent = SingleFragmentActivity.getIntent(
            targetContext,
            TestFragment::class,
            null
        )

        val scenario = ActivityScenario.launch<SingleFragmentActivity>(intent)
        scenario.use {
            it.onActivity { activity ->
                // Simulate back button press
                val backKeyEvent = KeyEvent(KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_BACK)
                val handled = activity.dispatchKeyEvent(backKeyEvent)

                // The event should be handled (by the parent's dispatchKeyEvent)
                assertThat("Back button should be handled by parent when fragment doesn't handle it", handled, `is`(true))
            }
        }
    }

    /**
     * Tests that when a fragment explicitly handles a key event (returns true),
     * that handling is respected and the parent's dispatchKeyEvent is not called.
     */
    @Test
    fun fragmentCanStillHandleOtherKeys() {
        val intent = SingleFragmentActivity.getIntent(
            targetContext,
            TestFragment::class,
            null
        )

        val scenario = ActivityScenario.launch<SingleFragmentActivity>(intent)
        scenario.use {
            it.onActivity { activity ->
                // Simulate a key that the fragment does handle (for example, DPAD_LEFT)
                val dpadLeftEvent = KeyEvent(KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_DPAD_LEFT)
                val handled = activity.dispatchKeyEvent(dpadLeftEvent)

                // The event should be handled by the fragment
                assertThat("DPAD_LEFT should be handled by the fragment", handled, `is`(true))
            }
        }
    }

    /**
     * Test fragment that implements DispatchKeyEventListener to simulate
     * the behavior of PreviewerFragment.
     */
    class TestFragment : Fragment(R.layout.single_fragment_activity), DispatchKeyEventListener {
        override fun dispatchKeyEvent(event: KeyEvent): Boolean {
            // Only handle DPAD_LEFT, let everything else fall through
            return when (event.keyCode) {
                KeyEvent.KEYCODE_DPAD_LEFT -> true // Simulate handling this key
                else -> false // Don't handle other keys (including BACK)
            }
        }

        override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
            super.onViewCreated(view, savedInstanceState)
        }
    }
}
